const parsed = $('Parse Slack Payload').item.json;

const privateMetadata = JSON.stringify({
  bird_conversation_id: parsed.bird_conversation_id,
  phone_number: parsed.lead_identifier,
  contact_name: parsed.contact_name,
  restaurant_name: parsed.company_name,
  country: parsed.country,
  segment: parsed.segment || '',
  slack_channel_id: parsed.slack_channel_id,
  original_message_ts: parsed.original_message_ts,
  slack_user_id: parsed.slack_user_id,
  slack_user_name: parsed.slack_user_name,
  lead_message: (parsed.lead_message || '').substring(0, 500),
  ai_generated_response: (parsed.ai_generated_response || '').substring(0, 300)
});

const leadMsgSafe = (parsed.lead_message || '').substring(0, 200);
const aiRespSafe = (parsed.ai_generated_response || '').substring(0, 200);
const contactInfo = (parsed.contact_name || 'Unknown') + ' - ' + (parsed.company_name || 'Unknown');

const viewsOpenModal = {
  trigger_id: parsed.trigger_id,
  view: {
    type: 'modal',
    callback_id: 'manual_response_modal',
    title: { type: 'plain_text', text: 'Send Manual Response' },
    submit: { type: 'plain_text', text: 'Send' },
    close: { type: 'plain_text', text: 'Discard' },
    private_metadata: privateMetadata,
    blocks: [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: '*To:* ' + contactInfo + '\n*Their message:*\n```' + leadMsgSafe + '```'
        }
      },
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: '*AI suggestion:*\n```' + aiRespSafe + '```'
        }
      },
      {
        type: 'input',
        block_id: 'manual_response_block',
        label: { type: 'plain_text', text: 'Your response' },
        element: {
          type: 'plain_text_input',
          action_id: 'manual_response_input',
          multiline: true,
          placeholder: { type: 'plain_text', text: 'Type your message to the prospect...' }
        }
      }
    ]
  }
};

return { json: { views_open_modal: viewsOpenModal } };

const payload = $input.first().json.body.payload;
const parsed = typeof payload === 'string' ? JSON.parse(payload) : payload;

const ctx = JSON.parse(parsed.view.private_metadata);
const manualResponse = (parsed.view.state.values?.manual_response_block?.manual_response_input?.value || '').trim();

return {
  json: {
    bird_conversation_id: ctx.bird_conversation_id,
    phone_number: ctx.phone_number,
    contact_name: ctx.contact_name,
    restaurant_name: ctx.restaurant_name,
    country: ctx.country,
    segment: ctx.segment || '',
    slack_channel_id: ctx.slack_channel_id,
    original_message_ts: ctx.original_message_ts,
    slack_user_id: parsed.user?.id || ctx.slack_user_id,
    slack_user_name: parsed.user?.name || parsed.user?.username || ctx.slack_user_name,
    lead_message: ctx.lead_message,
    ai_generated_response: ctx.ai_generated_response,
    manual_response: manualResponse,
    timestamp: new Date().toISOString()
  }
};

